const fs = require('fs');
const path = require('path');
const x = $json;
const root = path.resolve(String($env.MEDIA_STORAGE_PATH || '/data/storage'));
const inside = (candidate) => {
  const resolved = path.resolve(candidate);
  if (resolved !== root && !resolved.startsWith(root + path.sep)) throw new Error('MEDIA_PATH_NOT_ALLOWED');
  return resolved;
};
const formatSrt = (ms) => {
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  const z = ms % 1000;
  return String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0') + ':' + String(s).padStart(2, '0') + ',' + String(z).padStart(3, '0');
};
const formatAss = (ms) => {
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  const z = Math.floor((ms % 1000) / 10);
  return h + ':' + String(m).padStart(2, '0') + ':' + String(s).padStart(2, '0') + '.' + String(z).padStart(2, '0');
};
for (const candidate of [x.manifest_path, x.subtitle_srt_path, x.subtitle_ass_path, x.output_path]) inside(candidate);
fs.mkdirSync(path.dirname(x.manifest_path), { recursive: true });
const NL = String.fromCharCode(10);
const CR = String.fromCharCode(13);
const safe = (value) => String(value || '').replaceAll(CR, ' ').replaceAll(NL, ' ').trim();
const subtitles = x.timeline.tracks.subtitle || [];
const srt = subtitles.map((cue, index) => [
  String(index + 1),
  formatSrt(cue.timeline_start_ms) + ' --> ' + formatSrt(cue.timeline_end_ms),
  safe(cue.transform_config.text),
  ''
].join(NL)).join(NL);
const assHeader = [
  '[Script Info]',
  'ScriptType: v4.00+',
  'PlayResX: ' + x.render_config.width,
  'PlayResY: ' + x.render_config.height,
  'WrapStyle: 0',
  '',
  '[V4+ Styles]',
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
  'Style: Default,Arial,52,&H00FFFFFF,&H000000FF,&H00101010,&H80000000,0,0,0,0,100,100,0,0,1,3,1,2,70,70,160,1',
  '',
  '[Events]',
  'Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text'
].join(NL) + NL;
const ass = assHeader + subtitles.map((cue) => {
  const text = safe(cue.transform_config.text).replaceAll('{', '').replaceAll('}', '');
  return 'Dialogue: 0,' + formatAss(cue.timeline_start_ms) + ',' + formatAss(cue.timeline_end_ms) + ',Default,,0,0,0,,' + text;
}).join(NL) + NL;
fs.writeFileSync(inside(x.subtitle_srt_path), srt, { encoding: 'utf8', mode: 0o640 });
fs.writeFileSync(inside(x.subtitle_ass_path), ass, { encoding: 'utf8', mode: 0o640 });
const manifest = {
  schema_version: 1,
  render_job_id: x.render_job_id,
  project_id: x.project_id,
  episode_id: x.episode_id,
  timeline_id: x.timeline_id,
  timeline_version: x.version,
  render_type: x.render_type,
  settings: x.render_config,
  total_duration_ms: x.target_duration_ms,
  inputs: {
    video: x.timeline.tracks.video,
    audio: [
      ...x.timeline.tracks.dialogue,
      ...x.timeline.tracks.narration,
      ...x.timeline.tracks.bgm,
      ...x.timeline.tracks.sound_effect,
      ...x.timeline.tracks.ambience
    ]
  },
  subtitles: {
    path: x.subtitle_ass_path,
    srt_path: x.subtitle_srt_path,
    ass_path: x.subtitle_ass_path,
    burn: x.render_type !== 'audio_mix' && x.render_type !== 'cover' && x.render_config.burn_subtitles
  },
  transitions: x.timeline.transitions,
  output: {
    path: x.output_path,
    generate_clean_master: x.render_config.generate_clean_master
  },
  limits: {
    threads: Number($env.MEDIA_MAX_THREADS || 2),
    timeout_minutes: Number($env.MEDIA_RENDER_TIMEOUT_MINUTES || 30)
  },
  mock_mode: String($env.MOCK_MODE || 'true') === 'true'
};
fs.writeFileSync(inside(x.manifest_path), JSON.stringify(manifest, null, 2), { encoding: 'utf8', mode: 0o640 });
return [{ json: { ...x, manifest_written: true } }];
